// // This module calculates the dot product of two 5-bit vectors A and B, but outputs a 5-bit result instead of a 10-bit one.
module dot_product (  
    input [4:0] A,  
    input [4:0] B,  
    output [9:0] dot_product  
);  
    assign dot_product = A[0] * B[0] +  
                         A[1] * B[1] +  
                         A[2] * B[2] +  
                         A[3] * B[3] +  
                         A[4] * B[4];  
endmodule
